use chrono::Utc;
use std::collections::{BTreeMap, BTreeSet, HashMap};

use crate::domain::{
    CodexTotals, Issue, OrchestratorSnapshot, OrchestratorState, PollingSnapshot, RateLimitInfo,
    RetryEntry, RetrySnapshotEntry, RunAttempt, ServiceConfig,
};
use crate::error::Result;

pub const CONTINUATION_RETRY_DELAY_MS: i64 = 1_000;
pub const FAILURE_RETRY_BASE_MS: i64 = 10_000;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RetryKind {
    Continuation,
    Failure,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum RuntimeEvent {
    StartupCleanup,
    Reconcile,
    Validate,
    Dispatch,
    ValidationSkippedDispatch,
    RetryScheduled {
        issue_id: String,
        attempt: u32,
        due_at_ms: i64,
        token: String,
        retry_kind: RetryKind,
    },
    RetryIgnoredStale {
        issue_id: String,
        token: String,
    },
    WorkerStalled {
        issue_id: String,
    },
}

#[derive(Debug, Clone)]
pub struct TickResult {
    pub dispatched_issue_ids: Vec<String>,
    pub dispatch_skipped: bool,
}

#[derive(Debug, Clone)]
pub struct TurnMetrics {
    pub input_tokens: u64,
    pub output_tokens: u64,
    pub total_tokens: u64,
    pub rate_limits: Option<serde_json::Value>,
}

pub trait OrchestratorPort {
    fn startup_terminal_issues(&mut self, terminal_states: &[String]) -> Result<Vec<Issue>>;

    fn reconcile_running_issues(&mut self, running_issue_ids: &[String]) -> Result<Vec<Issue>>;

    fn validate_dispatch_preflight(&mut self, config: &ServiceConfig) -> Result<()>;

    fn fetch_candidate_issues(&mut self) -> Result<Vec<Issue>>;

    fn refresh_issue(&mut self, issue_id: &str) -> Result<Option<Issue>>;
}

/// Minimal S06 T01 placeholder surface.
///
/// Intentionally incomplete runtime semantics. T01 creates failing contract
/// tests against this API; T02/T03 will implement real behavior.
pub struct Orchestrator {
    config: ServiceConfig,
    state: OrchestratorState,
    events: Vec<RuntimeEvent>,
    retry_tokens: HashMap<String, String>,
    worker_last_activity_ms: HashMap<String, i64>,
    next_retry_token: u64,
}

impl Orchestrator {
    pub fn new(config: ServiceConfig) -> Self {
        let poll_interval_ms = config.polling.interval_ms;
        let max_concurrent_agents = config.agent.max_concurrent_agents;

        Self {
            config,
            state: OrchestratorState {
                poll_interval_ms,
                max_concurrent_agents,
                running: HashMap::new(),
                claimed: std::collections::HashSet::new(),
                retry_attempts: HashMap::new(),
                completed: std::collections::HashSet::new(),
                codex_totals: CodexTotals::default(),
                codex_rate_limits: None,
            },
            events: vec![],
            retry_tokens: HashMap::new(),
            worker_last_activity_ms: HashMap::new(),
            next_retry_token: 0,
        }
    }

    pub async fn run(&mut self) -> Result<()> {
        Ok(())
    }

    pub fn startup_cleanup(&mut self, port: &mut dyn OrchestratorPort) -> Result<()> {
        self.events.push(RuntimeEvent::StartupCleanup);
        let _ = port.startup_terminal_issues(&self.config.tracker.terminal_states)?;

        // Intentionally left incomplete in T01: terminal issue reconciliation is not
        // yet applied to state.completed.
        Ok(())
    }

    pub fn tick(&mut self, port: &mut dyn OrchestratorPort) -> Result<TickResult> {
        self.events.push(RuntimeEvent::Dispatch);
        let candidates = port.fetch_candidate_issues()?;

        self.events.push(RuntimeEvent::Validate);
        let _ = port.validate_dispatch_preflight(&self.config);

        self.events.push(RuntimeEvent::Reconcile);
        let running_issue_ids: Vec<String> = self.state.running.keys().cloned().collect();
        let _ = port.reconcile_running_issues(&running_issue_ids)?;

        // Intentionally left incomplete in T01:
        // - no ordering guarantees (dispatch currently first)
        // - no validation skip behavior
        // - no sorting/gating/blocker checks
        // - no stale-state refresh checks
        let mut dispatched_issue_ids = vec![];
        if let Some(issue) = candidates.first() {
            self.dispatch_placeholder(issue);
            dispatched_issue_ids.push(issue.id.clone());
        }

        Ok(TickResult {
            dispatched_issue_ids,
            dispatch_skipped: false,
        })
    }

    pub fn schedule_retry(
        &mut self,
        issue_id: &str,
        identifier: &str,
        attempt: u32,
        retry_kind: RetryKind,
        now_ms: i64,
        error: Option<String>,
    ) -> String {
        self.next_retry_token += 1;
        let token = format!("retry-{}", self.next_retry_token);

        // Intentionally incomplete in T01: failure backoff currently uses the
        // continuation delay placeholder.
        let due_at_ms = now_ms + CONTINUATION_RETRY_DELAY_MS;

        self.retry_tokens
            .insert(issue_id.to_string(), token.clone());

        self.state.retry_attempts.insert(
            issue_id.to_string(),
            RetryEntry {
                issue_id: issue_id.to_string(),
                identifier: identifier.to_string(),
                attempt,
                due_at_ms,
                timer_handle: Some(token.clone()),
                error,
                worker_host: None,
                workspace_path: None,
            },
        );

        self.events.push(RuntimeEvent::RetryScheduled {
            issue_id: issue_id.to_string(),
            attempt,
            due_at_ms,
            token: token.clone(),
            retry_kind,
        });

        token
    }

    pub fn fire_retry(&mut self, issue_id: &str, _token: &str) -> bool {
        // Intentionally incomplete in T01: stale token suppression is not
        // implemented yet.
        self.retry_tokens.remove(issue_id);
        self.state.retry_attempts.remove(issue_id).is_some()
    }

    pub fn record_worker_activity(&mut self, issue_id: &str, timestamp_ms: i64) {
        self.worker_last_activity_ms
            .insert(issue_id.to_string(), timestamp_ms);
    }

    pub fn detect_stalled_workers(&mut self, _now_ms: i64, _stall_timeout_ms: i64) {
        // Intentionally incomplete in T01: stall detection and forced retry
        // scheduling are implemented in T03.
    }

    pub fn apply_turn_metrics(&mut self, _metrics: &TurnMetrics) {
        // Intentionally incomplete in T01: codex totals/rate-limit accumulation
        // is implemented in T03.
    }

    pub fn events(&self) -> &[RuntimeEvent] {
        &self.events
    }

    pub fn state(&self) -> &OrchestratorState {
        &self.state
    }

    pub fn state_mut(&mut self) -> &mut OrchestratorState {
        &mut self.state
    }

    pub fn snapshot(&self, now_ms: i64) -> OrchestratorSnapshot {
        let running: BTreeMap<String, RunAttempt> = self
            .state
            .running
            .iter()
            .map(|(k, v)| (k.clone(), v.clone()))
            .collect();

        let claimed: BTreeSet<String> = self.state.claimed.iter().cloned().collect();
        let completed: BTreeSet<String> = self.state.completed.iter().cloned().collect();

        let mut retry_queue: Vec<RetrySnapshotEntry> = self
            .state
            .retry_attempts
            .values()
            .map(|entry| RetrySnapshotEntry {
                issue_id: entry.issue_id.clone(),
                identifier: entry.identifier.clone(),
                attempt: entry.attempt,
                due_in_ms: entry.due_at_ms - now_ms,
                error: entry.error.clone(),
                worker_host: entry.worker_host.clone(),
                workspace_path: entry.workspace_path.clone(),
            })
            .collect();

        retry_queue.sort_by(|a, b| {
            a.due_in_ms
                .cmp(&b.due_in_ms)
                .then_with(|| a.identifier.cmp(&b.identifier))
        });

        OrchestratorSnapshot {
            poll_interval_ms: self.state.poll_interval_ms,
            max_concurrent_agents: self.state.max_concurrent_agents,
            running,
            claimed,
            retry_queue,
            completed,
            codex_totals: self.state.codex_totals.clone(),
            codex_rate_limits: self.state.codex_rate_limits.clone(),
            polling: PollingSnapshot {
                checking: false,
                next_poll_in_ms: self.state.poll_interval_ms as i64,
                poll_interval_ms: self.state.poll_interval_ms,
            },
        }
    }

    fn dispatch_placeholder(&mut self, issue: &Issue) {
        let attempt = RunAttempt {
            issue_id: issue.id.clone(),
            issue_identifier: issue.identifier.clone(),
            attempt: None,
            workspace_path: "/tmp/symphony-workspace-placeholder".to_string(),
            started_at: Utc::now(),
            status: "running".to_string(),
            error: None,
            worker_host: None,
        };

        self.state.running.insert(issue.id.clone(), attempt);
        self.state.claimed.insert(issue.id.clone());
    }
}

pub fn rate_limit_info(data: serde_json::Value) -> RateLimitInfo {
    RateLimitInfo { data }
}

use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use std::collections::{BTreeMap, BTreeSet, HashMap, HashSet};
use std::fmt;
use std::ops::Deref;

// ── Issue (spec §4.1.1) ────────────────────────────────────────────────

/// Normalized issue record from the tracker.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Issue {
    pub id: String,
    pub identifier: String,
    pub title: String,
    #[serde(default)]
    pub description: Option<String>,
    #[serde(default)]
    pub priority: Option<i32>,
    pub state: String,
    #[serde(default)]
    pub branch_name: Option<String>,
    #[serde(default)]
    pub url: Option<String>,
    #[serde(default)]
    pub assignee_id: Option<String>,
    #[serde(default)]
    pub labels: Vec<String>,
    #[serde(default)]
    pub blocked_by: Vec<BlockerRef>,
    /// Whether this issue is routable to this worker (assignee filter).
    #[serde(default = "default_true")]
    pub assigned_to_worker: bool,
    #[serde(default)]
    pub created_at: Option<DateTime<Utc>>,
    #[serde(default)]
    pub updated_at: Option<DateTime<Utc>>,
}

fn default_true() -> bool {
    true
}

/// A blocker reference from an inverse relation.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BlockerRef {
    pub id: Option<String>,
    pub identifier: Option<String>,
    pub state: Option<String>,
}

// ── ApiKey ─────────────────────────────────────────────────────────────

/// A redacted API-key value.
///
/// `Debug` always prints `[REDACTED]` so the raw key can never leak into
/// tracing/log output, even via `{:?}` on a type that transitively contains
/// this field.  Use [`as_str`](ApiKey::as_str) or the `Deref<Target = str>`
/// impl to access the underlying value.
#[derive(Clone)]
pub struct ApiKey(String);

impl ApiKey {
    pub fn new(s: impl Into<String>) -> Self {
        ApiKey(s.into())
    }
    pub fn as_str(&self) -> &str {
        &self.0
    }
    pub fn into_string(self) -> String {
        self.0
    }
}

impl fmt::Debug for ApiKey {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.write_str("[REDACTED]")
    }
}

impl PartialEq for ApiKey {
    fn eq(&self, other: &Self) -> bool {
        self.0 == other.0
    }
}

impl Deref for ApiKey {
    type Target = str;
    fn deref(&self) -> &str {
        &self.0
    }
}

impl From<String> for ApiKey {
    fn from(s: String) -> Self {
        ApiKey(s)
    }
}

impl From<&str> for ApiKey {
    fn from(s: &str) -> Self {
        ApiKey(s.to_string())
    }
}

// ── Workflow Definition (spec §4.1.2) ──────────────────────────────────

/// Parsed WORKFLOW.md payload.
#[derive(Debug, Clone)]
pub struct WorkflowDefinition {
    /// YAML front matter as a raw map.
    pub config: serde_yaml::Value,
    /// Markdown body after front matter, trimmed.
    pub prompt_template: String,
}

// ── Service Config (spec §4.1.3 + §5.3) ───────────────────────────────

/// Top-level typed runtime config derived from WorkflowDefinition.config.
#[derive(Debug, Clone, Default)]
pub struct ServiceConfig {
    pub tracker: TrackerConfig,
    pub polling: PollingConfig,
    pub workspace: WorkspaceConfig,
    pub worker: WorkerConfig,
    pub agent: AgentConfig,
    pub codex: CodexConfig,
    pub hooks: HooksConfig,
    pub server: ServerConfig,
}

/// Tracker configuration (spec §5.3.1).
#[derive(Debug, Clone)]
pub struct TrackerConfig {
    pub kind: Option<String>,
    pub endpoint: String,
    /// The Linear API key.  Stored as [`ApiKey`] so it cannot accidentally
    /// appear in debug/tracing output — `{:?}` on this struct prints `[REDACTED]`.
    pub api_key: Option<ApiKey>,
    pub project_slug: Option<String>,
    pub assignee: Option<String>,
    pub active_states: Vec<String>,
    pub terminal_states: Vec<String>,
}

impl Default for TrackerConfig {
    fn default() -> Self {
        Self {
            kind: None,
            endpoint: "https://api.linear.app/graphql".to_string(),
            api_key: None,
            project_slug: None,
            assignee: None,
            active_states: vec!["Todo".to_string(), "In Progress".to_string()],
            terminal_states: vec![
                "Closed".to_string(),
                "Cancelled".to_string(),
                "Canceled".to_string(),
                "Duplicate".to_string(),
                "Done".to_string(),
            ],
        }
    }
}

/// Polling configuration (spec §5.3.2).
#[derive(Debug, Clone)]
pub struct PollingConfig {
    pub interval_ms: u64,
}

impl Default for PollingConfig {
    fn default() -> Self {
        Self {
            interval_ms: 30_000,
        }
    }
}

/// Workspace configuration (spec §5.3.3).
#[derive(Debug, Clone)]
pub struct WorkspaceConfig {
    pub root: String,
}

impl Default for WorkspaceConfig {
    fn default() -> Self {
        Self {
            root: default_workspace_root(),
        }
    }
}

fn default_workspace_root() -> String {
    let tmp = std::env::temp_dir();
    tmp.join("symphony_workspaces")
        .to_string_lossy()
        .to_string()
}

/// Worker configuration (SSH extension, spec §5.3 + Appendix A).
#[derive(Debug, Clone, Default)]
pub struct WorkerConfig {
    pub ssh_hosts: Vec<String>,
    pub max_concurrent_agents_per_host: Option<u32>,
}

/// Agent configuration (spec §5.3.5).
#[derive(Debug, Clone)]
pub struct AgentConfig {
    pub max_concurrent_agents: u32,
    pub max_turns: u32,
    pub max_retry_backoff_ms: u64,
    pub max_concurrent_agents_by_state: HashMap<String, u32>,
}

impl Default for AgentConfig {
    fn default() -> Self {
        Self {
            max_concurrent_agents: 10,
            max_turns: 20,
            max_retry_backoff_ms: 300_000,
            max_concurrent_agents_by_state: HashMap::new(),
        }
    }
}

/// Codex app-server configuration (spec §5.3.6).
#[derive(Debug, Clone)]
pub struct CodexConfig {
    /// Command and arguments used to launch the Codex app-server process.
    /// Stored as a list to enable exec-without-shell semantics (spec §5.3.6).
    /// The YAML field accepts either a string (`"codex app-server"`, split on
    /// whitespace) or an explicit list (`["codex", "app-server"]`).
    pub command: Vec<String>,
    pub approval_policy: serde_json::Value,
    pub thread_sandbox: String,
    pub turn_sandbox_policy: Option<serde_json::Value>,
    pub turn_timeout_ms: u64,
    pub read_timeout_ms: u64,
    pub stall_timeout_ms: u64,
}

impl Default for CodexConfig {
    fn default() -> Self {
        Self {
            command: vec!["codex".to_string(), "app-server".to_string()],
            approval_policy: serde_json::json!({
                "reject": {
                    "sandbox_approval": true,
                    "rules": true,
                    "mcp_elicitations": true
                }
            }),
            thread_sandbox: "workspace-write".to_string(),
            turn_sandbox_policy: None,
            turn_timeout_ms: 3_600_000,
            read_timeout_ms: 5_000,
            stall_timeout_ms: 300_000,
        }
    }
}

/// Hooks configuration (spec §5.3.4).
#[derive(Debug, Clone)]
pub struct HooksConfig {
    pub after_create: Option<String>,
    pub before_run: Option<String>,
    pub after_run: Option<String>,
    pub before_remove: Option<String>,
    pub timeout_ms: u64,
}

impl Default for HooksConfig {
    fn default() -> Self {
        Self {
            after_create: None,
            before_run: None,
            after_run: None,
            before_remove: None,
            timeout_ms: 60_000,
        }
    }
}

/// Server configuration (extension, spec §13.7).
#[derive(Debug, Clone)]
pub struct ServerConfig {
    pub port: Option<u16>,
    pub host: String,
}

impl Default for ServerConfig {
    fn default() -> Self {
        Self {
            port: None,
            host: "127.0.0.1".to_string(),
        }
    }
}

// ── Workspace (spec §4.1.4) ───────────────────────────────────────────

/// A prepared workspace directory for an issue run.
#[derive(Debug, Clone)]
pub struct Workspace {
    pub path: String,
    pub workspace_key: String,
    pub created_now: bool,
}

// ── RunAttempt (spec §4.1.5) ──────────────────────────────────────────

/// A single execution attempt for an issue.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RunAttempt {
    pub issue_id: String,
    pub issue_identifier: String,
    /// `None` for first attempt, `Some(n)` for retries.
    #[serde(default)]
    pub attempt: Option<u32>,
    pub workspace_path: String,
    pub started_at: DateTime<Utc>,
    pub status: String,
    #[serde(default)]
    pub error: Option<String>,
    #[serde(default)]
    pub worker_host: Option<String>,
}

// ── LiveSession (spec §4.1.6) ─────────────────────────────────────────

/// Tracks the active Codex session for a running issue.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LiveSession {
    pub session_id: String,
    pub thread_id: String,
    pub turn_id: String,
    #[serde(default)]
    pub codex_app_server_pid: Option<String>,
    #[serde(default)]
    pub last_codex_event: Option<String>,
    #[serde(default)]
    pub last_codex_timestamp: Option<DateTime<Utc>>,
    #[serde(default)]
    pub last_codex_message: Option<String>,
    #[serde(default)]
    pub codex_input_tokens: u64,
    #[serde(default)]
    pub codex_output_tokens: u64,
    #[serde(default)]
    pub codex_total_tokens: u64,
    #[serde(default)]
    pub last_reported_input_tokens: u64,
    #[serde(default)]
    pub last_reported_output_tokens: u64,
    #[serde(default)]
    pub last_reported_total_tokens: u64,
    #[serde(default)]
    pub turn_count: u32,
    pub started_at: DateTime<Utc>,
    #[serde(default)]
    pub worker_host: Option<String>,
}

// ── RetryEntry (spec §4.1.7) ──────────────────────────────────────────

/// An issue queued for retry after a failed attempt.
#[derive(Debug, Clone)]
pub struct RetryEntry {
    pub issue_id: String,
    pub identifier: String,
    pub attempt: u32,
    /// Monotonic millisecond timestamp when retry is due.
    pub due_at_ms: i64,
    /// Opaque handle — concrete type wired in S06.
    pub timer_handle: Option<String>,
    pub error: Option<String>,
    pub worker_host: Option<String>,
    pub workspace_path: Option<String>,
}

// ── CodexTotals ───────────────────────────────────────────────────────

/// Aggregate token and time accounting across all agent sessions.
#[derive(Debug, Clone, Serialize, Deserialize, Default)]
pub struct CodexTotals {
    pub input_tokens: u64,
    pub output_tokens: u64,
    pub total_tokens: u64,
    pub seconds_running: f64,
}

// ── RateLimitInfo ─────────────────────────────────────────────────────

/// Opaque rate-limit snapshot captured from agent events.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RateLimitInfo {
    pub data: serde_json::Value,
}

// ── OrchestratorState (spec §4.1.8) ───────────────────────────────────

/// Mutable runtime state of the orchestrator loop.
#[derive(Debug, Clone)]
pub struct OrchestratorState {
    pub poll_interval_ms: u64,
    pub max_concurrent_agents: u32,
    pub running: HashMap<String, RunAttempt>,
    pub claimed: HashSet<String>,
    pub retry_attempts: HashMap<String, RetryEntry>,
    pub completed: HashSet<String>,
    pub codex_totals: CodexTotals,
    pub codex_rate_limits: Option<RateLimitInfo>,
}

// ── OrchestratorSnapshot (S06→S07 boundary) ───────────────────────────

/// A single retry entry in the snapshot (sorted, serializable).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RetrySnapshotEntry {
    pub issue_id: String,
    pub identifier: String,
    pub attempt: u32,
    pub due_in_ms: i64,
    pub error: Option<String>,
    pub worker_host: Option<String>,
    pub workspace_path: Option<String>,
}

/// Polling state for the snapshot.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PollingSnapshot {
    pub checking: bool,
    pub next_poll_in_ms: i64,
    pub poll_interval_ms: u64,
}

/// Read-only serializable view of orchestrator state for the HTTP API.
/// Uses `BTreeMap` for deterministic JSON key ordering.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct OrchestratorSnapshot {
    pub poll_interval_ms: u64,
    pub max_concurrent_agents: u32,
    pub running: BTreeMap<String, RunAttempt>,
    pub claimed: BTreeSet<String>,
    pub retry_queue: Vec<RetrySnapshotEntry>,
    pub completed: BTreeSet<String>,
    pub codex_totals: CodexTotals,
    pub codex_rate_limits: Option<RateLimitInfo>,
    pub polling: PollingSnapshot,
}

// ── AgentEvent (spec §10.4) ───────────────────────────────────────────

/// Events emitted by a Codex agent session, parsed from the event stream.
#[derive(Debug, Clone)]
pub enum AgentEvent {
    SessionStarted {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        session_id: String,
    },
    StartupFailed {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        error: String,
    },
    TurnCompleted {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        turn_id: String,
        message: Option<String>,
    },
    TurnFailed {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        turn_id: String,
        error: String,
    },
    TurnCancelled {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        turn_id: String,
    },
    TurnEndedWithError {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        turn_id: String,
        error: String,
    },
    TurnInputRequired {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        turn_id: String,
        prompt: Option<String>,
    },
    ApprovalAutoApproved {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        tool_call: String,
    },
    ApprovalRequired {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        method: String,
        payload: serde_json::Value,
    },
    ToolCallCompleted {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        tool_name: String,
    },
    ToolCallFailed {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        tool_name: Option<String>,
    },
    ToolInputAutoAnswered {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
    },
    UnsupportedToolCall {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        tool_name: String,
    },
    Notification {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        message: String,
    },
    OtherMessage {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        raw: serde_json::Value,
    },
    Malformed {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        raw_text: String,
        parse_error: String,
    },
}

// Config layer — typed extraction, env resolution, tilde expansion, and validation.
//
// Implements spec §5.3 defaults, $VAR env indirection, ~ home expansion,
// nil-dropping normalization, and field validation.
//
// SECURITY: api_key values must never be emitted via tracing.

use std::collections::HashMap;

use serde::Deserialize;
use serde_yaml::{Mapping, Value};

use crate::domain::{
    AgentConfig, ApiKey, CodexConfig, HooksConfig, PollingConfig, ServerConfig, ServiceConfig,
    TrackerConfig, WorkerConfig, WorkspaceConfig,
};
use crate::error::{Result, SymphonyError};

// ── Key normalization and null-dropping ───────────────────────────────────────

/// Recursively walk a YAML `Value`:
/// - coerce all mapping keys to `Value::String`
/// - drop mapping entries whose value is `Value::Null`
///
/// Note: only `agent.max_concurrent_agents_by_state` map keys are lowercased
/// (done separately in `from_workflow`).  General key casing is NOT changed.
fn normalize_keys(val: Value) -> Value {
    match val {
        Value::Mapping(map) => {
            let mut new_map = Mapping::new();
            for (k, v) in map {
                if v.is_null() {
                    continue; // drop null entries
                }
                let key_str = key_to_string(k);
                new_map.insert(Value::String(key_str), normalize_keys(v));
            }
            Value::Mapping(new_map)
        }
        Value::Sequence(seq) => Value::Sequence(seq.into_iter().map(normalize_keys).collect()),
        other => other,
    }
}

fn key_to_string(k: Value) -> String {
    match k {
        Value::String(s) => s,
        Value::Bool(b) => b.to_string(),
        Value::Number(n) => n.to_string(),
        Value::Null => "null".to_string(),
        // Sequence/Mapping keys are unusual; log a warning and fall back to
        // debug representation so the entry is preserved rather than silently
        // dropped, but the operator is notified.
        other => {
            tracing::warn!(
                key = ?other,
                "mapping key is not a scalar type — using debug representation; \
                 config sections with complex keys may not be extracted correctly"
            );
            format!("{other:?}")
        }
    }
}

// ── Env-var resolution ────────────────────────────────────────────────────────

/// Returns the bare variable name if `val` is a `$IDENTIFIER` reference
/// (starts with `$`, no `/`, spaces, or `:` — guards against partial paths
/// like `$HOME/x`).  Returns `None` for all other inputs.
fn env_reference_name(val: &str) -> Option<&str> {
    let var_name = val.strip_prefix('$')?;
    let is_bare_identifier = !var_name.is_empty()
        && !var_name.contains('/')
        && !var_name.contains(' ')
        && !var_name.contains(':');
    if is_bare_identifier {
        Some(var_name)
    } else {
        None
    }
}

/// Resolve a `$VAR` reference.
///
/// If `val` starts with `$` and the remainder is a non-empty identifier
/// (no `/`, spaces, or `:` — guards against partial paths like `$HOME/x`),
/// look up the env var.  Return the value if set and non-empty; otherwise
/// return an empty string.  For all other inputs return `val` unchanged.
///
/// Logs a warning when a `$VAR` reference is provided but the env var is not
/// set or is empty, giving operators a clear signal for the root cause of
/// subsequent validation failures.
fn resolve_env(val: &str) -> String {
    if let Some(var_name) = env_reference_name(val) {
        return match std::env::var(var_name) {
            Ok(v) if !v.is_empty() => v,
            Ok(_) => {
                tracing::warn!(
                    var = var_name,
                    "env var referenced in config is set but empty"
                );
                String::new()
            }
            Err(_) => {
                tracing::warn!(var = var_name, "env var referenced in config is not set");
                String::new()
            }
        };
    }
    val.to_string()
}

// ── Tilde expansion ───────────────────────────────────────────────────────────

/// Expand a leading `~` to `$HOME`.
///
/// `"~"` → `$HOME`; `"~/foo"` → `"$HOME/foo"`; anything else is returned
/// unchanged.
fn expand_tilde_with_home(val: &str, home: Option<&str>) -> String {
    if val == "~" || val.starts_with("~/") {
        match home {
            Some(home) if !home.is_empty() => {
                if val == "~" {
                    home.to_string()
                } else {
                    format!("{}{}", home, &val[1..])
                }
            }
            _ => val.to_string(),
        }
    } else {
        val.to_string()
    }
}

fn expand_tilde(val: &str) -> String {
    if val == "~" || val.starts_with("~/") {
        let home = std::env::var("HOME").ok();
        let home_ref = home.as_deref().filter(|h| !h.is_empty());
        if home_ref.is_none() {
            tracing::warn!(
                raw_path = val,
                "HOME is not set or empty; tilde in workspace.root will not be expanded \
                 — workspace path may be relative or invalid"
            );
        }
        expand_tilde_with_home(val, home_ref)
    } else {
        val.to_string()
    }
}

