// WorkflowStore — live-watched config store with hot-reload.
//
// Holds the current effective (WorkflowDefinition, ServiceConfig) under a
// std::sync::RwLock, runs a background thread that watches the workflow file
// via `notify::recommended_watcher`, debounces events (400 ms), and
// atomically reloads on change.  Invalid reloads keep the last-known-good
// config and log the error.
//
// A `force_reload()` async method provides the dispatch-preflight reload
// trigger.
//
// SECURITY: api_key values must never be emitted via tracing.  `ServiceConfig`
// is never logged directly — only field names are logged, never values.

use std::path::{Path, PathBuf};
use std::sync::{Arc, RwLock};
use std::time::Duration;

use notify::{RecommendedWatcher, RecursiveMode, Watcher};

use crate::domain::{ServiceConfig, WorkflowDefinition};
use crate::error::{Result, SymphonyError};
use crate::{config, workflow};

// ── Type alias ────────────────────────────────────────────────────────────────

type EffectiveConfig = (WorkflowDefinition, ServiceConfig);

// ── WorkflowStore ─────────────────────────────────────────────────────────────

/// Owns the parsed WORKFLOW.md and its derived [`ServiceConfig`], and
/// hot-reloads the file when it changes on disk.
///
/// Last-known-good semantics: a reload failure (parse error, invalid config)
/// leaves the previous config in place.  Call [`effective_config`] to obtain
/// a snapshot of the current state.
///
/// [`effective_config`]: WorkflowStore::effective_config
pub struct WorkflowStore {
    path: PathBuf,
    inner: Arc<RwLock<EffectiveConfig>>,
    /// Keeps the watcher alive for the lifetime of the store.
    /// Dropping it would stop file-system notifications.
    _watcher: RecommendedWatcher,
}

impl WorkflowStore {
    /// Construct a [`WorkflowStore`] from a WORKFLOW.md path.
    ///
    /// Parses the file immediately.  Returns an error if the initial parse or
    /// config extraction fails (fail-fast on syntax/shape errors).  Does NOT
    /// call `config::validate()` — validation is the orchestrator's
    /// dispatch-preflight responsibility; the store accepts any syntactically
    /// valid config to allow iterative hot-reload fixes without restarting.
    ///
    /// Starts a background thread that debounces file-system events and
    /// hot-reloads the config when the watched file changes.
    pub fn new(path: &Path) -> Result<Self> {
        // Canonicalize early so all internal comparisons (including notify
        // event paths) use the real filesystem path.  On macOS /tmp is a
        // symlink to /private/tmp; without this, direct equality checks against
        // notify-reported paths would fail.  Fall back to the original path if
        // canonicalization is unavailable (e.g., path does not exist yet).
        let path = path.canonicalize().unwrap_or_else(|_| path.to_path_buf());

        // ── 1. Load initial config — fail fast on parse/extraction errors ─
        let def = workflow::parse_workflow(&path)?;
        let cfg = config::from_workflow(&def.config)?;

        let inner: Arc<RwLock<EffectiveConfig>> = Arc::new(RwLock::new((def, cfg)));

        // ── 2. Set up mpsc channel for notify events ───────────────────────
        let (tx, rx) = std::sync::mpsc::channel::<notify::Event>();

        // ── 3. Create notify watcher ───────────────────────────────────────
        let watched_path = path.clone();
        let mut watcher = notify::recommended_watcher(move |res: notify::Result<notify::Event>| {
            match res {
                Ok(e) => {
                    if event_mentions_workflow(&e, &watched_path) {
                        // Best-effort send — receiver may be gone if store dropped.
                        let _ = tx.send(e);
                    }
                }
                Err(e) => {
                    // OS-level watcher failures (inotify limit, permission denied,
                    // FSEvents overflow, etc.) mean the watcher is permanently broken
                    // and hot-reload is dead until the process restarts.
                    tracing::error!(
                        reason = %e,
                        "file-system watcher error — hot-reload is disabled until restart"
                    );
                }
            }
        })
        .map_err(|e| SymphonyError::Other(format!("watcher creation failed: {e}")))?;

        // Watch the parent directory with non-recursive mode.
        // Watching the parent (rather than the file itself) covers editors and
        // tools that use atomic-rename writes (write to temp → rename).
        let watch_dir = path.parent().ok_or_else(|| {
            SymphonyError::Other(format!(
                "cannot determine parent directory for watch path: {}",
                path.display()
            ))
        })?;

        watcher
            .watch(watch_dir, RecursiveMode::NonRecursive)
            .map_err(|e| SymphonyError::Other(format!("watcher setup failed: {e}")))?;

        // ── 4. Spawn debounce thread ───────────────────────────────────────
        //
        // We use a plain std::thread (not tokio::spawn) so that the store
        // can be constructed in both sync (`#[test]`) and async
        // (`#[tokio::test]`) contexts without requiring an active tokio
        // runtime.
        {
            let path_t = path.clone();
            let inner_t = inner.clone();

            std::thread::spawn(move || {
                while rx.recv().is_ok() {
                    // Debounce: sleep 400 ms, then drain any events
                    // that arrived in the meantime, before reloading.
                    std::thread::sleep(Duration::from_millis(400));
                    while rx.try_recv().is_ok() {}

                    force_reload_inner(&path_t, &inner_t);
                    // Receiver error means the sender (watcher) was
                    // dropped — store has been destroyed, exit thread.
                }
            });
        }

        Ok(WorkflowStore {
            path,
            inner,
            _watcher: watcher,
        })
    }

    /// Return a snapshot of the current `(WorkflowDefinition, ServiceConfig)`.
    ///
    /// The snapshot is a clone — callers can inspect it freely without holding
    /// a lock.  This method is safe to call from both sync and async contexts.
    ///
    /// If the read lock is poisoned (another thread panicked while holding the
    /// write lock), the last-written value is recovered and returned rather
    /// than propagating a panic.
    pub fn effective_config(&self) -> EffectiveConfig {
        match self.inner.read() {
            Ok(guard) => guard.clone(),
            Err(poisoned) => {
                tracing::warn!(
                    "WorkflowStore read lock was poisoned — recovering last-known-good config"
                );
                poisoned.into_inner().clone()
            }
        }
    }

    /// Force an immediate reload of the workflow file, bypassing the debounce
    /// buffer.
    ///
    /// If the reload fails, the last-known-good config is preserved and the
    /// error is logged and returned to the caller.
    ///
    /// Useful as a dispatch-preflight check: the orchestrator can call this
    /// right before dispatching a new agent session to pick up any changes.
    ///
    /// NOTE: This method does NOT call `config::validate()`.  The orchestrator
    /// must call `config::validate(&store.effective_config().1)` separately as
    /// a dispatch preflight.  See D017.
    pub async fn force_reload(&self) -> Result<()> {
        let path = self.path.clone();
        let inner = self.inner.clone();
        tokio::task::spawn_blocking(move || match try_load(&path) {
            Ok(effective) => apply_effective(&path, &inner, effective),
            Err(e) => {
                tracing::error!(
                    path = %path.display(),
                    reason = %e,
                    "workflow reload failed — keeping last known good"
                );
                Err(e)
            }
        })
        .await
        .map_err(|e| SymphonyError::Other(format!("reload task panicked: {e}")))?
    }
}

// ── Internal helpers ──────────────────────────────────────────────────────────

/// Attempt to parse and extract config from the workflow file, then atomically
/// update the store.  On failure, log the error and keep the last-known-good
/// config.
fn force_reload_inner(path: &Path, inner: &Arc<RwLock<EffectiveConfig>>) {
    let result = try_load(path).and_then(|effective| apply_effective(path, inner, effective));
    if let Err(e) = result {
        tracing::error!(
            path = %path.display(),
            reason = %e,
            "workflow reload failed — keeping last known good"
        );
    }
}

fn apply_effective(
    path: &Path,
    inner: &Arc<RwLock<EffectiveConfig>>,
    effective: EffectiveConfig,
) -> Result<()> {
    let mut guard = match inner.write() {
        Ok(guard) => guard,
        Err(poisoned) => {
            tracing::warn!(
                path = %path.display(),
                "WorkflowStore write lock was poisoned — recovering and overwriting with fresh config"
            );
            poisoned.into_inner()
        }
    };
    *guard = effective;
    tracing::info!(
        path = %path.display(),
        "workflow reloaded successfully"
    );
    Ok(())
}

fn event_mentions_workflow(event: &notify::Event, workflow_path: &Path) -> bool {
    event
        .paths
        .iter()
        .any(|event_path| event_path_matches_workflow(event_path, workflow_path))
}

fn event_path_matches_workflow(event_path: &Path, workflow_path: &Path) -> bool {
    let same_filename = event_path.file_name() == workflow_path.file_name();
    event_path == workflow_path
        || event_path.ends_with(workflow_path)
        || (same_filename
            && matches!(
                (event_path.parent(), workflow_path.parent()),
                (Some(event_parent), Some(workflow_parent))
                    if event_parent == workflow_parent || event_parent.ends_with(workflow_parent)
            ))
}

/// Parse and extract — returning the full [`EffectiveConfig`] or an error.
///
/// Does not call `config::validate()` (validation is the orchestrator's
/// dispatch-preflight responsibility).  Does not touch the store state.
fn try_load(path: &Path) -> Result<EffectiveConfig> {
    let def = workflow::parse_workflow(path)?;
    let cfg = config::from_workflow(&def.config)?;
    Ok((def, cfg))
}

#[cfg(test)]
mod tests {
    use super::*;
    use notify::event::{EventAttributes, EventKind};

    fn make_event(paths: &[&str]) -> notify::Event {
        notify::Event {
            kind: EventKind::Any,
            paths: paths.iter().map(PathBuf::from).collect(),
            attrs: EventAttributes::new(),
        }
    }

    #[test]
    fn event_matches_exact_workflow_path() {
        let workflow = Path::new("/tmp/work/WORKFLOW.md");
        let event = make_event(&["/tmp/work/WORKFLOW.md"]);
        assert!(event_mentions_workflow(&event, workflow));
    }

    #[test]
    fn event_matches_when_workflow_path_is_relative() {
        let workflow = Path::new("WORKFLOW.md");
        let event = make_event(&["/tmp/work/WORKFLOW.md"]);
        assert!(event_mentions_workflow(&event, workflow));
    }

    #[test]
    fn event_ignores_unrelated_paths() {
        let workflow = Path::new("/tmp/work/WORKFLOW.md");
        let event = make_event(&["/tmp/work/README.md", "/tmp/work/.tmp123"]);
        assert!(!event_mentions_workflow(&event, workflow));
    }
}

use std::collections::HashMap;

use chrono::{Duration, Utc};

use symphony::domain::{
    AgentConfig, BlockerRef, Issue, ServiceConfig, TrackerConfig, WorkflowDefinition,
};
use symphony::error::{Result, SymphonyError};
use symphony::orchestrator::{
    Orchestrator, OrchestratorPort, RetryKind, RuntimeEvent, TurnMetrics,
    CONTINUATION_RETRY_DELAY_MS,
};

#[derive(Default)]
struct FakePort {
    calls: Vec<String>,
    terminal_issues: Vec<Issue>,
    reconciled_issues: Vec<Issue>,
    candidate_issues: Vec<Issue>,
    refreshed_issues: HashMap<String, Option<Issue>>,
    validate_should_fail: bool,
}

impl FakePort {
    fn call_history(&self) -> &[String] {
        &self.calls
    }
}

impl OrchestratorPort for FakePort {
    fn startup_terminal_issues(&mut self, _terminal_states: &[String]) -> Result<Vec<Issue>> {
        self.calls.push("startup_terminal_issues".to_string());
        Ok(self.terminal_issues.clone())
    }

    fn reconcile_running_issues(&mut self, _running_issue_ids: &[String]) -> Result<Vec<Issue>> {
        self.calls.push("reconcile_running_issues".to_string());
        Ok(self.reconciled_issues.clone())
    }

    fn validate_dispatch_preflight(&mut self, _config: &ServiceConfig) -> Result<()> {
        self.calls.push("validate_dispatch_preflight".to_string());
        if self.validate_should_fail {
            Err(SymphonyError::MissingLinearApiToken)
        } else {
            Ok(())
        }
    }

    fn fetch_candidate_issues(&mut self) -> Result<Vec<Issue>> {
        self.calls.push("fetch_candidate_issues".to_string());
        Ok(self.candidate_issues.clone())
    }

    fn refresh_issue(&mut self, issue_id: &str) -> Result<Option<Issue>> {
        self.calls.push(format!("refresh_issue:{issue_id}"));
        Ok(self
            .refreshed_issues
            .get(issue_id)
            .cloned()
            .unwrap_or_else(|| None))
    }
}

fn test_config(max_concurrent_agents: u32) -> ServiceConfig {
    let mut config = ServiceConfig::default();
    config.tracker = TrackerConfig {
        kind: Some("linear".to_string()),
        api_key: Some("test-key".into()),
        project_slug: Some("project".to_string()),
        active_states: vec!["Todo".to_string(), "In Progress".to_string()],
        terminal_states: vec!["Done".to_string(), "Canceled".to_string()],
        ..TrackerConfig::default()
    };
    config.agent = AgentConfig {
        max_concurrent_agents,
        max_turns: 20,
        max_retry_backoff_ms: 60_000,
        max_concurrent_agents_by_state: HashMap::from([
            ("todo".to_string(), 1_u32),
            ("in progress".to_string(), 1_u32),
        ]),
    };
    config
}

fn issue(
    id: &str,
    identifier: &str,
    state: &str,
    priority: Option<i32>,
    created_at_offset_secs: i64,
) -> Issue {
    Issue {
        id: id.to_string(),
        identifier: identifier.to_string(),
        title: format!("Issue {identifier}"),
        description: Some("orchestrator test issue".to_string()),
        priority,
        state: state.to_string(),
        branch_name: None,
        url: None,
        assignee_id: None,
        labels: vec![],
        blocked_by: vec![],
        assigned_to_worker: true,
        created_at: Some(Utc::now() + Duration::seconds(created_at_offset_secs)),
        updated_at: Some(Utc::now()),
    }
}

#[test]
fn test_startup_terminal_cleanup_marks_terminal_issues_completed() {
    let mut orchestrator = Orchestrator::new(test_config(2));
    let mut port = FakePort {
        terminal_issues: vec![issue("issue-closed", "SIM-10", "Done", Some(1), 0)],
        ..FakePort::default()
    };

    let result = orchestrator.startup_cleanup(&mut port);
    assert!(
        result.is_ok(),
        "startup cleanup should run without transport errors: {result:?}"
    );

    let completed = &orchestrator.state().completed;
    assert!(
        completed.contains("issue-closed"),
        "startup cleanup must mark terminal tracker issues as completed before first dispatch"
    );
}

#[test]
fn test_tick_reconcile_before_validate_before_dispatch() {
    let mut orchestrator = Orchestrator::new(test_config(2));
    let mut port = FakePort {
        candidate_issues: vec![issue("issue-1", "SIM-1", "Todo", Some(2), 0)],
        ..FakePort::default()
    };

    let result = orchestrator.tick(&mut port);
    assert!(result.is_ok(), "tick should complete: {result:?}");

    assert_eq!(
        port.call_history(),
        [
            "reconcile_running_issues",
            "validate_dispatch_preflight",
            "fetch_candidate_issues"
        ],
        "tick must execute reconcile -> validate -> dispatch fetch ordering"
    );
}

#[test]
fn test_preflight_validation_failure_skips_dispatch_but_reconcile_continues() {
    let mut orchestrator = Orchestrator::new(test_config(2));
    let mut port = FakePort {
        validate_should_fail: true,
        candidate_issues: vec![issue("issue-2", "SIM-2", "Todo", Some(1), 0)],
        ..FakePort::default()
    };

    let result = orchestrator.tick(&mut port);
    assert!(result.is_ok(), "tick should not crash on preflight failure");

    let called_reconcile = port
        .call_history()
        .iter()
        .any(|call| call == "reconcile_running_issues");
    assert!(
        called_reconcile,
        "reconcile must still run when preflight validation fails"
    );

    let called_dispatch_fetch = port
        .call_history()
        .iter()
        .any(|call| call == "fetch_candidate_issues");
    assert!(
        !called_dispatch_fetch,
        "candidate fetch/dispatch must be skipped on preflight validation failure"
    );

    let has_skip_signal = orchestrator
        .events()
        .iter()
        .any(|event| matches!(event, RuntimeEvent::ValidationSkippedDispatch));
    assert!(
        has_skip_signal,
        "orchestrator should emit a validation skip signal for diagnostics"
    );
}

#[test]
fn test_candidate_sorting_and_gating_rules() {
    let mut orchestrator = Orchestrator::new(test_config(1));

    let mut blocked = issue("issue-blocked", "SIM-20", "Todo", Some(0), 0);
    blocked.blocked_by.push(BlockerRef {
        id: Some("issue-parent".to_string()),
        identifier: Some("SIM-5".to_string()),
        state: Some("In Progress".to_string()),
    });

    let highest = issue("issue-highest", "SIM-21", "Todo", Some(1), 10);
    let lower = issue("issue-lower", "SIM-22", "Todo", Some(3), -10);

    let mut port = FakePort {
        candidate_issues: vec![blocked, lower.clone(), highest.clone()],
        ..FakePort::default()
    };

    let tick = orchestrator.tick(&mut port);
    assert!(tick.is_ok(), "tick should return a result");

    let dispatched = tick
        .ok()
        .map(|value| value.dispatched_issue_ids)
        .unwrap_or_default();

    assert_eq!(
        dispatched,
        vec![highest.id],
        "dispatch must sort by priority/created_at/identifier and gate blocked issues"
    );
}

#[test]
fn test_predispatch_refresh_rejects_stale_state() {
    let mut orchestrator = Orchestrator::new(test_config(2));
    let stale_candidate = issue("issue-stale", "SIM-30", "In Progress", Some(1), 0);
    let refreshed_terminal = issue("issue-stale", "SIM-30", "Done", Some(1), 0);

    let mut port = FakePort {
        candidate_issues: vec![stale_candidate],
        refreshed_issues: HashMap::from([("issue-stale".to_string(), Some(refreshed_terminal))]),
        ..FakePort::default()
    };

    let result = orchestrator.tick(&mut port);
    assert!(result.is_ok(), "tick should handle refresh checks");

    let refresh_called = port
        .call_history()
        .iter()
        .any(|call| call == "refresh_issue:issue-stale");
    assert!(
        refresh_called,
        "orchestrator must refresh issue state by id before dispatch"
    );

    let running_has_stale = orchestrator.state().running.contains_key("issue-stale");
    assert!(
        !running_has_stale,
        "orchestrator must reject dispatch when refreshed state is no longer active"
    );
}

#[test]
fn test_retry_scheduling_continuation_and_failure_backoff_rules() {
    let mut orchestrator = Orchestrator::new(test_config(2));
    let now_ms = 10_000;

    let continuation_token = orchestrator.schedule_retry(
        "issue-continuation",
        "SIM-40",
        1,
        RetryKind::Continuation,
        now_ms,
        None,
    );

    let failure_token = orchestrator.schedule_retry(
        "issue-failure",
        "SIM-41",
        3,
        RetryKind::Failure,
        now_ms,
        Some("agent exited: :boom".to_string()),
    );

    assert!(
        continuation_token != failure_token,
        "retry scheduling should issue unique retry tokens"
    );

    let continuation_due = orchestrator
        .state()
        .retry_attempts
        .get("issue-continuation")
        .map(|entry| entry.due_at_ms)
        .unwrap_or_default();
    assert_eq!(
        continuation_due,
        now_ms + CONTINUATION_RETRY_DELAY_MS,
        "continuation retry should schedule at +1s"
    );

    let failure_due = orchestrator
        .state()
        .retry_attempts
        .get("issue-failure")
        .map(|entry| entry.due_at_ms)
        .unwrap_or_default();
    assert_eq!(
        failure_due,
        now_ms + 40_000,
        "failure retry attempt=3 should schedule with exponential backoff base 10s"
    );
}

#[test]
fn test_stale_retry_timer_is_ignored() {
    let mut orchestrator = Orchestrator::new(test_config(2));
    let now_ms = 20_000;

    let current_token = orchestrator.schedule_retry(
        "issue-stale-retry",
        "SIM-50",
        2,
        RetryKind::Failure,
        now_ms,
        Some("agent exited: :boom".to_string()),
    );

    let stale_token = "retry-stale-token".to_string();
    let consumed = orchestrator.fire_retry("issue-stale-retry", &stale_token);

    assert!(
        !consumed,
        "stale retry token should be ignored instead of consuming retry queue entries"
    );

    let still_present = orchestrator
        .state()
        .retry_attempts
        .contains_key("issue-stale-retry");
    assert!(
        still_present,
        "stale retry firing must keep the newer retry entry in place"
    );

    let ignored_event_present = orchestrator.events().iter().any(|event| {
        matches!(
            event,
            RuntimeEvent::RetryIgnoredStale { issue_id, token }
                if issue_id == "issue-stale-retry" && token == &stale_token
        )
    });

    assert!(
        ignored_event_present,
        "stale retry suppression should emit retry_ignored_stale diagnostic event"
    );

    let queue_token = orchestrator
        .state()
        .retry_attempts
        .get("issue-stale-retry")
        .and_then(|entry| entry.timer_handle.clone())
        .unwrap_or_default();

    assert_eq!(
        queue_token, current_token,
        "queue should preserve the current retry token"
    );
}

#[test]
fn test_stall_detection_schedules_forced_retry() {
    let mut orchestrator = Orchestrator::new(test_config(2));

    orchestrator.state_mut().running.insert(
        "issue-stalled".to_string(),
        symphony::domain::RunAttempt {
            issue_id: "issue-stalled".to_string(),
            issue_identifier: "SIM-60".to_string(),
            attempt: Some(1),
            workspace_path: "/tmp/workspace-stalled".to_string(),
            started_at: Utc::now(),
            status: "running".to_string(),
            error: None,
            worker_host: None,
        },
    );

    let now_ms = 200_000;
    orchestrator.record_worker_activity("issue-stalled", now_ms - 31_000);
    orchestrator.detect_stalled_workers(now_ms, 30_000);

    let has_retry = orchestrator
        .state()
        .retry_attempts
        .contains_key("issue-stalled");
    assert!(
        has_retry,
        "stalled worker should be moved into retry queue with forced retry"
    );

    let stalled_event = orchestrator
        .events()
        .iter()
        .any(|event| matches!(event, RuntimeEvent::WorkerStalled { issue_id } if issue_id == "issue-stalled"));
    assert!(
        stalled_event,
        "stalled worker path should emit worker_stalled diagnostic event"
    );
}

#[test]
fn test_codex_totals_and_rate_limits_accumulate_into_snapshot() {
    let mut orchestrator = Orchestrator::new(test_config(2));

    orchestrator.apply_turn_metrics(&TurnMetrics {
        input_tokens: 10,
        output_tokens: 5,
        total_tokens: 15,
        rate_limits: Some(serde_json::json!({ "remaining": 99 })),
    });

    orchestrator.apply_turn_metrics(&TurnMetrics {
        input_tokens: 7,
        output_tokens: 3,
        total_tokens: 10,
        rate_limits: Some(serde_json::json!({ "remaining": 88 })),
    });

    let snapshot = orchestrator.snapshot(0);

    assert_eq!(
        snapshot.codex_totals.input_tokens, 17,
        "input token totals should accumulate across turns"
    );
    assert_eq!(
        snapshot.codex_totals.output_tokens, 8,
        "output token totals should accumulate across turns"
    );
    assert_eq!(
        snapshot.codex_totals.total_tokens, 25,
        "total tokens should accumulate across turns"
    );

    let remaining = snapshot
        .codex_rate_limits
        .as_ref()
        .and_then(|value| value.data.get("remaining"))
        .and_then(|value| value.as_i64())
        .unwrap_or_default();

    assert_eq!(
        remaining, 88,
        "snapshot should retain latest observed rate-limit payload"
    );
}

#[test]
fn test_snapshot_exposes_running_and_retry_diagnostics() {
    let mut orchestrator = Orchestrator::new(test_config(2));

    orchestrator.state_mut().running.insert(
        "issue-running".to_string(),
        symphony::domain::RunAttempt {
            issue_id: "issue-running".to_string(),
            issue_identifier: "SIM-70".to_string(),
            attempt: Some(2),
            workspace_path: "/tmp/workspace-running".to_string(),
            started_at: Utc::now(),
            status: "failed".to_string(),
            error: Some("worker failed".to_string()),
            worker_host: Some("worker-a".to_string()),
        },
    );

    orchestrator.schedule_retry(
        "issue-running",
        "SIM-70",
        3,
        RetryKind::Failure,
        1_000,
        Some("worker failed".to_string()),
    );

    let snapshot = orchestrator.snapshot(1_000);

    let has_running = snapshot.running.contains_key("issue-running");
    assert!(
        has_running,
        "snapshot should include currently running entries for diagnostics"
    );

    let retry_error = snapshot
        .retry_queue
        .first()
        .and_then(|entry| entry.error.clone())
        .unwrap_or_default();

    assert_eq!(
        retry_error, "worker failed",
        "snapshot retry queue should include error diagnostics for failed runs"
    );
}

